// Robustecimiento del nodo Limpia - Analista ARH
const UF_VALOR = 38000; // Valor referencial para cálculo de acción legal
const LIMITE_DEMANDA_UF = 35;

return $input.all().map(item => {
  const raw = item.json;

  // 1. Rescate de Identificadores (Crucial para Expedientes_Core)
  const idMail = raw.id || raw.messageId || "Sin_ID";

  // 2. Limpieza profunda de Texto
  let cleanText = (raw.text || "")
    .replace(/<\/?[^>]+(>|$)/g, "") // Elimina HTML si existiera
    .replace(/\r?\n|\r/g, " ")      // Linealiza el texto
    .replace(/\s\s+/g, ' ')         // Remueve espacios extra
    .trim()
    .substring(0, 5000);            // Límite de seguridad de tokens

  // 3. Metadata del correo
  const subject = raw.subject || "Sin Asunto";
  const fromEmail = raw.from?.value[0]?.address || "desconocido";

  return {
    json: {
      id_mail: idMail,
      text_to_process: cleanText,
      metadata: {
        asunto: subject,
        remitente: fromEmail,
        fecha_recepcion: raw.date
      },
      // Pasamos el valor de la UF para que la IA lo use en el prompt si es necesario
      contexto_legal: {
        valor_uf_ref: UF_VALOR,
        umbral_demanda: UF_VALOR * LIMITE_DEMANDA_UF
      }
    }
  };
});

// 1. Definición de constantes para lógica de negocio
const VALOR_UF = 38000; 
const UMBRAL_PESOS = 35 * VALOR_UF; // Límite para Demanda Civil (> 1.330.000 CLP)

const nuevosItems = [];

for (const item of $input.all()) {
  try {
    // 2. Extraer y limpiar el JSON proveniente del nodo de IA
    let rawOutput = item.json.output;
    const jsonString = rawOutput.replace(/```json|```/gi, '').trim();
    const dataIA = JSON.parse(jsonString);

    // 3. Normalización del Monto (Quitar caracteres no numéricos)
    const montoLimpio = parseFloat(dataIA.monto_reclamado.toString().replace(/[^0-9.]/g, '')) || 0;

    // 4. Lógica de Acción Legal (Ley 21.234)
    // Si el monto es superior a 35 UF, es Demanda Civil.
    const tipoAccionCalculada = montoLimpio > UMBRAL_PESOS ? "Demanda Civil" : "Medida Prejudicial";

    // 5. Construcción del objeto final para Supabase (Tabla: Expedientes_Core)
    nuevosItems.push({
      json: {
        "ID_mail": dataIA.id_mail || "Sin_ID", // El ID del mail es la llave universal 
        "Folio_Banco": Array.isArray(dataIA.folios_banco) ? dataIA.folios_banco.join(', ') : dataIA.folios_banco,
        "Banco_Cliente": dataIA.banco_cliente || "No detectado",
        "RUT_Cliente": dataIA.rut_cliente,
        "Monto_Reclamado": montoLimpio,
        "Tipo_Acción": tipoAccionCalculada,
        "Estado_Ley_21234": "Ingresado",
        "Nombre cliente": dataIA.nombre_cliente,
        "Domicilio cliente": dataIA.domicilio_cliente || "No especificado"
      }
    });
  } catch (error) {
    nuevosItems.push({ 
      json: { 
        error: "Error en transformación de datos", 
        detalles: error.message,
        raw: item.json.output 
      } 
    });
  }
}

return nuevosItems;

