// Propósito: Extraer la URL pública/interna de Google Drive y limpiar el objeto JSON

return $input.all().map(item => {
  const driveData = item.json;

  // Extraemos la URL de visualización. 
  // Si necesitas el ID para construir una URL personalizada, usa driveData.id
  const urlDrive = driveData.webViewLink || "";

  return {
    json: {
      // Mantenemos identificadores si existen en el nodo anterior para no romper la relación
      id_maestro_rel: driveData.id_maestro_rel || driveData.id_maestro || null,
      nombre_archivo: driveData.name,
      url_drive: urlDrive,
      file_id: driveData.id,
      mime_type: driveData.mimeType
    }
  };
});

// Nodo: Limpiar_Supabase_Storage
return $input.all().map(item => {
  const key = item.json.Key;
  // Extraemos el UUID que está entre / / en la Key
  const match = key.match(/evidencias\/(.*?)\//);
  const id_maestro = match ? match[1] : null;

  return {
    json: {
      id_maestro: id_maestro,
      storage_key: key,
      storage_id: item.json.Id,
      // Extraemos el nombre del archivo para un segundo nivel de match si fuera necesario
      nombre_archivo: key.split('/').pop().replace('clean_', '')
    }
  };
});

